proof fn phi_1_always_unfold_intensional_bridge(ex: Execution<int>, p: TempPred<int>, i: nat)
    requires
        always(p).satisfied_by(ex),
    ensures
        p.satisfied_by(ex.suffix(i)),
{
    always_unfold::<int>(ex, p);
}

proof fn phi_2_implies_apply_closure_bridge(ex: Execution<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        p.satisfied_by(ex),
        (p.pred)(ex) ==> (q.pred)(ex),
    ensures
        q.satisfied_by(ex),
{
    implies_apply::<int>(ex, p, q);
}

proof fn phi_3_entails_preserved_always_any_spec(p: TempPred<int>, q: TempPred<int>, spec: TempPred<int>)
    requires
        p.entails(q),
        spec.entails(always(p)),
    ensures
        spec.entails(always(q)),
{
    entails_preserved_by_always::<int>(p, q);
    assert forall |ex| #[trigger] spec.satisfied_by(ex) implies always(q).satisfied_by(ex) by {
        implies_apply::<int>(ex, spec, always(p));
        implies_apply::<int>(ex, always(p), always(q));
    };
}

proof fn phi_4_always_entails_monotone_chain(p: TempPred<int>, q: TempPred<int>, r: TempPred<int>)
    requires
        p.entails(q),
        q.entails(r),
    ensures
        always(p).entails(always(r)),
{
    assert forall |ex| always(p).satisfied_by(ex) implies always(r).satisfied_by(ex) by {
        assert forall |i: nat| r.satisfied_by(#[trigger] ex.suffix(i)) by {
            always_unfold::<int>(ex, p);
            implies_apply::<int>(ex.suffix(i), p, q);
            implies_apply::<int>(ex.suffix(i), q, r);
        };
    };
}

proof fn phi_5_valid_implies_entails_anything(p: TempPred<int>, spec: TempPred<int>)
    requires
        valid(p),
    ensures
        spec.entails(p),
{
    assert forall |ex| #[trigger] spec.satisfied_by(ex) implies p.satisfied_by(ex) by {
        implies_apply::<int>(ex, spec, p);
    };
}
